    27  template <typename LogRequest, typename LogResponse> class GrpcAccessLogClient {
    28  public:
    29    virtual ~GrpcAccessLogClient() = default;
    30    virtual bool isConnected() PURE;
    31    virtual bool log(const LogRequest& request) PURE;
    32
    33  protected:
    34    GrpcAccessLogClient(const Grpc::RawAsyncClientSharedPtr& client,
    35                        const Protobuf::MethodDescriptor& service_method,
    36                        OptRef<const envoy::config::core::v3::RetryPolicy> retry_policy)
    37        : client_(client), service_method_(service_method),
    38          opts_(createRequestOptionsForRetry(retry_policy)) {}
    39
    40    Grpc::AsyncClient<LogRequest, LogResponse> client_;
    41    const Protobuf::MethodDescriptor& service_method_;
    42    const Http::AsyncClient::RequestOptions opts_;
