   293  MetadataFilter::MetadataFilter(const envoy::config::accesslog::v3::MetadataFilter& filter_config,
   294                                 Server::Configuration::CommonFactoryContext& context)
   295      : default_match_(PROTOBUF_GET_WRAPPED_OR_DEFAULT(filter_config, match_if_key_not_found, true)),
   296        filter_(filter_config.matcher().filter()) {
   297
   298    if (filter_config.has_matcher()) {
   299      auto& matcher_config = filter_config.matcher();
   300
   301      for (const auto& seg : matcher_config.path()) {
   302        path_.push_back(seg.key());
   303      }
   304
   305      // Matches if the value equals the configured 'MetadataMatcher' value.
   306      const auto& val = matcher_config.value();
   307      value_matcher_ = Matchers::ValueMatcher::create(val, context);
   308    }
   309
   310    // Matches if the value is present in dynamic metadata
   311    auto present_val = envoy::type::matcher::v3::ValueMatcher();
   312    present_val.set_present_match(true);
   313    present_matcher_ = Matchers::ValueMatcher::create(present_val, context);
   314  }
   315
   316  bool MetadataFilter::evaluate(const Formatter::HttpFormatterContext&,
   317                                const StreamInfo::StreamInfo& info) const {
   318    const auto& value =
   319        Envoy::Config::Metadata::metadataValue(&info.dynamicMetadata(), filter_, path_);
   320    // If the key corresponds to a set value in dynamic metadata, return true if the value matches the
   321    // the configured 'MetadataMatcher' value and false otherwise
   322    if (present_matcher_->match(value)) {
   323      return value_matcher_ && value_matcher_->match(value);
   324    }
   325
   326    // If the key does not correspond to a set value in dynamic metadata, return true if
   327    // 'match_if_key_not_found' is set to true and false otherwise
   328    return default_match_;
   329  }
