    34  AccessLog::InstanceSharedPtr
    35  FluentdAccessLogFactory::createAccessLogInstance(const Protobuf::Message& config,
    36                                                   AccessLog::FilterPtr&& filter,
    37                                                   Server::Configuration::FactoryContext& context) {
    38    const auto& proto_config = MessageUtil::downcastAndValidate<
    39        const envoy::extensions::access_loggers::fluentd::v3::FluentdAccessLogConfig&>(
    40        config, context.messageValidationVisitor());
    41
    42    absl::Status status = context.serverFactoryContext().clusterManager().checkActiveStaticCluster(
    43        proto_config.cluster());
    44    if (!status.ok()) {
    45      throw EnvoyException(fmt::format("cluster '{}' was not found", proto_config.cluster()));
    46    }
    47
    48    if (proto_config.has_retry_options() && proto_config.retry_options().has_backoff_options()) {
    49      status = BackOffStrategyUtils::validateBackOffStrategyConfig(
    50          proto_config.retry_options().backoff_options(), DefaultBaseBackoffIntervalMs,
    51          DefaultMaxBackoffIntervalFactor);
    52      if (!status.ok()) {
    53        throw EnvoyException(
    54            "max_backoff_interval must be greater or equal to base_backoff_interval");
    55      }
    56    }
    57
    58    // Supporting nested object serialization is more complex with MessagePack.
    59    // Using an already existing JSON formatter, and later converting the JSON string to a msgpack
    60    // payload.
    61    // TODO(ohadvano): Improve the formatting operation by creating a dedicated formatter that
    62    //                 will directly serialize the record to msgpack payload.
    63    auto commands =
    64        Formatter::SubstitutionFormatStringUtils::parseFormatters(proto_config.formatters(), context);
    65    Formatter::FormatterPtr json_formatter =
    66        Formatter::SubstitutionFormatStringUtils::createJsonFormatter(proto_config.record(), true,
    67                                                                      false, false, commands);
    68    FluentdFormatterPtr fluentd_formatter =
    69        std::make_unique<FluentdFormatterImpl>(std::move(json_formatter));
    70
    71    return std::make_shared<FluentdAccessLog>(
    72        std::move(filter), std::move(fluentd_formatter),
    73        std::make_shared<FluentdAccessLogConfig>(proto_config),
    74        context.serverFactoryContext().threadLocal(),
    75        context.serverFactoryContext().api().randomGenerator(),
    76        getAccessLoggerCacheSingleton(context.serverFactoryContext()));
    77  }
