    45    case envoy::extensions::access_loggers::file::v3::FileAccessLog::AccessLogFormatCase::
    46        kTypedJsonFormat: {
    47      envoy::config::core::v3::SubstitutionFormatString sff_config;
    48      *sff_config.mutable_json_format() = fal_config.typed_json_format();
    49      formatter = Formatter::SubstitutionFormatStringUtils::fromProtoConfig(sff_config, context);
